/* * * V i t a l s * * */
import * as React from 'react';
import {useNavigate, useLocation, useLoaderData} from 'react-router-dom';
import useUIC from '../../UIcontext';
import APIaccess from '../../apiaccess';

import './Settings.css';

let accessAPI = APIaccess();


export default function Settings({ 
	current,
	setCurrent,
	sectionClass, 
	refe,
	socketMessage,
	setSocketMessage 
}) {

	let navigate = useNavigate();
	// const location = useLocation();
	// const data = useLoaderData();
	const { logout } = useUIC();
	const username = sessionStorage.getItem('userName');
	const [currentSettings, setCurrentSettings] = React.useState();
	const [privacyOption, setPrivacyOption] = React.useState();

	const [exit, setExit] = React.useReducer(state => !state, false)
	const [section, setSection] = React.useState([
		{
			profile: false,	
		},
		{
			photo: false,	
		},
		{
			username: false,	
		},
		{
			biography: false,	
		},
		{
			changePassword: false,
		},
		{
			privacy: false,
		},
		{
			invitation: false,
		}
	])
	const [changedUsername, setChangedUsername] = React.useState("");
	const [biography, setBiography] = React.useState("");
	const [currentPass, setCurrentPass] = React.useState("");
	const [newPass, setNewPass] = React.useState("");
	const [profilePhoto, setProfilePhoto] = React.useState({
		url: null,
		content: ''
	});
	const [isLogout, setLogout] = React.useReducer(state => !state, false);

	const [dataLoaded, setDataLoaded] = React.useState(false);

	const updateUserSettings = async() => {

		let data = await accessAPI.userSettings({option: 'getUserSettings'});
        setCurrentSettings(data);
        setPrivacyOption(data.privacy);
        setDataLoaded(true);
	}

	const openSection = (selection) => {
		if(selection == 'profile') {
			if(section.profile) {
				setSection({
					...section,
					profile: false
				}) 
			} else {
				setSection({
					...section,
					profile: true,
					privacy: false,
					invitation: false,
					changePassword: false,
					biography: false,
					username: false,
					photo: false,
				})
			}
		}

		else if(selection == 'photo') {

			if (section.photo) {
				setSection({
					...section,
					photo: false,
					username: false,
					biography: false,
					changePassword: false
				})
			}
			else {
				setSection({
					...section,
					photo: true,
					username: false,
					biography: false,
					changePassword: false
				}) 
			} 
		}

		else if(selection == 'username') {

			if(section.username) {
				setSection({
					...section,
					username: false,
					photo: false,
					biography: false,
					changePassword: false
				})
			}
			else {
				setSection({
					...section,
					username: true,
					photo: false,
					biography: false,
					changePassword: false
				}) 
			} 
		}
		
		else if(selection == 'biography') {
			
			if(section.biography) {
				setSection({
					...section,
					biography: false,
					username: false,
					photo: false,
					changePassword: false
				})
			}
			else {
				setSection({
					...section,
					biography: true,
					username: false,
					photo: false,
					changePassword: false
				})
			}
		}

		else if(selection == 'changePassword') {

			if(section.changePassword) {
				setSection({
					...section,
					changePassword: false,
					biography: false,
					username: false,
					photo: false,
				})
			}
			else {
				setSection({
					...section,
					changePassword: true,
					biography: false,
					username: false,
					photo: false,
				}) 
			}
		}	



		else if(selection == 'privacy') {
			if(section.privacy) {
				setSection({
					...section,
					privacy: false
				}) 
			} 
			else {
				setSection({
					...section,
					privacy: true,
					profile: false,
					invitation: false
				})
			}
		} 
		else if(selection == 'invitation') {
			if(section.invitation) {
				setSection({
					...section,
					invitation: false
				}) 
			} 
			else {
				setSection({
					...section,
					invitation: true,
					profile: false,
					privacy: false
				})
			}
		} 
	}

	const handleChange = (event) => {
 
		if(event.target.name == 'image') {
			setProfilePhoto({
				url: URL.createObjectURL(event.target.files[0]),
				content: event.target.files[0]
			});
		} 

		else if(event.target.name == 'username') {
			setChangedUsername(event.target.value)
			// console.log(event.target.value)
		}

		else if(event.target.name == 'biography') {
			setBiography(event.target.value)
		}

		else if(event.target.name == 'password') {
			setCurrentPass(event.target.value)
		}
		else if(event.target.name == 'newPass') {
			setNewPass(event.target.value)
		}
	}

	const handleSubmit = (event) => {

		//sends necessary data over via socketMessage
		if(event.target.name == 'photoSubmit') {
			if(profilePhoto.content == "") {
				setSocketMessage({
					type: 'error',
					message: 'Please upload a photo'
				})
			}
			else {
				setSocketMessage({
					content: profilePhoto.content,
					action: 'profilePhoto'
				})
			}
		}

		else if(event.target.name == 'usernameUpdate') {
			if(changedUsername == "") {
				setSocketMessage({
					type: 'error',
					message: 'Please enter a new username'
				})
			} else {
				setSocketMessage({
					action: 'usernameUpdate',
					newUsername: changedUsername
				})
			}
		}

		else if(event.target.name == 'bioUpdate') {
			setSocketMessage({
					action: 'bioUpdate',
					biography: biography,
					option: 'biography'
				})
		}

		else if(event.target.name == 'changePassword') {
			if(currentPass == ''|| newPass == '') {
				setSocketMessage({
					type: 'error',
					message: 'One or both of the fields are empty'
				})
			}
			else {
				setSocketMessage({
					action: 'changePassword',
					currentPassword: currentPass,
					newPassword: newPass
				})
			}
		}

		else if(event.target.name == 'privacyOn') {
			setSocketMessage({
				action: 'privacy',
				option: 'privacy',
				state: 'On'
			})
		}

		else if(event.target.name == 'privacyHalf') {
			setSocketMessage({
				action: 'privacy',
				option: 'privacy',
				state: 'Half'
			})
		}

		else if(event.target.name == 'privacyOff') {
			setSocketMessage({
				action: 'privacy',
				option: 'privacy',
				state: 'Off'
			})
		}
	}

	React.useEffect(()=> {
		updateUserSettings();
	},[])


	if(dataLoaded) {
		return (
			<div id="settings" className={ `${sectionClass.settings}` } ref={refe}>
				
			</div>
		)
	}
	
}
